import Vue from 'vue'
import VueRouter from 'vue-router'
import Home from '../views/Home.vue'

/**
 * SEO config
 */
import homeSeo from './SEO/homeSeo'
import aboutSeo from './SEO/aboutSeo'
import bandsSeo from './SEO/bandsSeo'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    component: Home,
    meta: homeSeo
  },
  {
    path: '/info',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/About.vue'),
    meta: aboutSeo
  },
  {
    path: '/proyectos',
    component: () => import(/* webpackChunkName: "bands" */ '../views/Bands.vue'),
    meta: {
      title: 'band Page',
      metaTags: [
        {
          name: 'description',
          content: 'The about page of our example app.'
        },
        {
          property: 'og:description',
          content: 'The about page of our example app.'
        }
      ]
    }
  },
  {
    path: '/proyectos/ogun',
    component: () => import(/* webpackChunkName: "bands" */ '../views/Band.vue'),
    meta: bandsSeo
  },
  {
    path: '/contactos/',
    component: () => import(/* webpackChunkName: "bands" */ '../views/Contact.vue'),
    meta: bandsSeo
  },
  {
    path: '*',
    redirect: '/'
  }
]

const router = new VueRouter({
  mode: 'history',
  routes
})

export default router
